 1	import React from 'react';
 2	import {
 3	  Select,
 4	  SelectOption,
 5	  SelectList,
 6	  MenuToggle,
 7	  MenuToggleElement,
 8	  SelectOptionProps,
 9	} from '@patternfly/react-core';
10	
11	interface BasicSelectProps {
12	  id: string;
13	  width: number;
14	  placeholder: string;
15	  options: SelectOptionProps[];
16	  selected?: string;
17	  setSelected: (value?: string) => void;
18	}
19	
20	export function BasicSelect({
21	  id,
22	  width,
23	  placeholder,
24	  options,
25	  selected,
26	  setSelected,
27	}: BasicSelectProps) {
28	  const [isOpen, setIsOpen] = React.useState(false);
29	
30	  const onToggleClick = () => {
31	    setIsOpen(!isOpen);
32	  };
33	
34	  const onSelect = (
35	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
36	    value: string | number | undefined,
37	  ) => {
38	    setSelected(value as string);
39	    setIsOpen(false);
40	  };
41	
42	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
43	    <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen} style={{ width }}>
44	      {selected ? options.find((o) => o.value === selected)?.children ?? placeholder : placeholder}
45	    </MenuToggle>
46	  );
47	
48	  return (
49	    <Select
50	      id={id}
51	      isOpen={isOpen}
52	      selected={selected}
53	      onSelect={onSelect}
54	      onOpenChange={(isOpen) => setIsOpen(isOpen)}
55	      toggle={toggle}
56	      shouldFocusToggleOnSelect
57	    >
58	      <SelectList>
59	        {options.map((option) => (
60	          <SelectOption key={option.value} value={option.value}>
61	            {option.children}
62	          </SelectOption>
63	        ))}
64	      </SelectList>
65	    </Select>
66	  );
67	}

